#include <stdio.h>
#include <stdlib.h>

int gcd_int(int a, int b){
    if(a<0) a=-a; if(b<0) b=-b;
    while(b){int t=a%b; a=b; b=t;} return a;
}

typedef struct{int dx, dy;} Dir;
int cmp_dir(const void *a, const void *b){
    Dir *x=(Dir*)a, *y=(Dir*)b;
    if(x->dx!=y->dx) return x->dx - y->dx;
    return x->dy - y->dy;
}

int main(){
    int T; if(scanf("%d",&T)!=1) return 0;
    while(T--){
        int N; scanf("%d",&N);
        int *X = (int*)malloc(N*sizeof(int));
        int *Y = (int*)malloc(N*sizeof(int));
        for(int i=0;i<N;i++) scanf("%d %d",&X[i],&Y[i]);
        int best = (N>0)?1:0;
        Dir *arr = (Dir*)malloc((N-1)*sizeof(Dir));
        for(int i=0;i<N;i++){
            int cnt=0;
            for(int j=0;j<N;j++) if(j!=i){
                int dx = X[j]-X[i];
                int dy = Y[j]-Y[i];
                if(dx==0 && dy==0) continue; // not possible because distinct
                int g = gcd_int(dx,dy);
                dx/=g; dy/=g;
                if(dx<0){dx=-dx; dy=-dy;}
                else if(dx==0 && dy<0){dy=-dy;}
                arr[cnt].dx=dx; arr[cnt].dy=dy; cnt++;
            }
            qsort(arr,cnt,sizeof(Dir),cmp_dir);
            int cur=1; for(int k=1;k<cnt;k++){
                if(arr[k].dx==arr[k-1].dx && arr[k].dy==arr[k-1].dy) cur++; else cur=1;
                if(cur+1>best) best=cur+1; // +1 for anchor
            }
        }
        printf("%d\n",best);
        free(X); free(Y); free(arr);
    }
    return 0;
}

