import java.io.*;
import java.util.*;
public class Main {
    static int gcd(int a,int b){
        if(a<0) a=-a; if(b<0) b=-b;
        while(b!=0){int t=a%b; a=b; b=t;}
        return a;
    }
    static class Pair {
        int dx, dy;
        Pair(int dx,int dy){this.dx=dx; this.dy=dy;}
        @Override public int hashCode(){return Objects.hash(dx,dy);}        
        @Override public boolean equals(Object o){
            if(this==o) return true;
            if(!(o instanceof Pair)) return false;
            Pair p=(Pair)o; return dx==p.dx && dy==p.dy;
        }
    }
    public static void main(String[] args) throws Exception {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        StringTokenizer st;
        int T = Integer.parseInt(br.readLine().trim());
        StringBuilder out = new StringBuilder();
        while(T-- > 0){
            int N = Integer.parseInt(br.readLine().trim());
            int[] X = new int[N];
            int[] Y = new int[N];
            for(int i=0;i<N;i++){
                st = new StringTokenizer(br.readLine());
                X[i] = Integer.parseInt(st.nextToken());
                Y[i] = Integer.parseInt(st.nextToken());
            }
            int best = (N>0)?1:0;
            for(int i=0;i<N;i++){
                HashMap<Pair,Integer> map = new HashMap<>(N*2);
                for(int j=0;j<N;j++) if(j!=i){
                    int dx = X[j]-X[i];
                    int dy = Y[j]-Y[i];
                    int g = gcd(dx,dy);
                    dx/=g; dy/=g;
                    if(dx<0){dx=-dx; dy=-dy;}
                    else if(dx==0 && dy<0){dy=-dy;}
                    Pair p = new Pair(dx,dy);
                    int cnt = map.getOrDefault(p,0)+1;
                    map.put(p,cnt);
                    best = Math.max(best, cnt+1);
                }
            }
            out.append(best).append('\n');
        }
        System.out.print(out.toString());
    }
}

