const fs = require('fs');
const input = fs.readFileSync(0,'utf-8').trim().split(/\s+/).map(Number);
let idx = 0;
const T = input[idx++];
let outputs = [];
function gcd(a,b){
    a = Math.abs(a); b = Math.abs(b);
    while(b!==0){ let t = a % b; a = b; b = t; }
    return a;
}
for(let t=0;t<T;t++){
    const N = input[idx++];
    let pts = new Array(N);
    for(let i=0;i<N;i++){
        const x = input[idx++];
        const y = input[idx++];
        pts[i] = [x,y];
    }
    let best = N>0?1:0;
    for(let i=0;i<N;i++){
        const map = new Map();
        const [xi,yi] = pts[i];
        for(let j=0;j<N;j++) if(j!==i){
            const [xj,yj] = pts[j];
            let dx = xj - xi;
            let dy = yj - yi;
            const g = gcd(dx,dy);
            dx /= g; dy /= g;
            if(dx<0){dx=-dx; dy=-dy;}
            else if(dx===0 && dy<0){dy=-dy;}
            const key = dx+','+dy;
            const cnt = (map.get(key)||0)+1;
            map.set(key,cnt);
            if(cnt+1>best) best = cnt+1;
        }
    }
    outputs.push(String(best));
}
console.log(outputs.join('\n'));

